#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    qsort(a, n, sizeof(int), compare);
    int median = a[n / 2];
    int operations = 0;
    for (int i = 0; i < n; i++) {
        operations += abs(a[i] - median);
    }
    printf("%d\n", operations);
    return 0;
}

