code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }
        Arrays.sort(a);
        int median = a[n / 2];
        int operations = 0;
        for (int i = 0; i < n; i++) {
            operations += Math.abs(a[i] - median);
        }
        System.out.println(operations);
    }
}

