const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        a.sort((x, y) => x - y);
        const median = a[Math.floor(n / 2)];
        const operations = a.reduce((acc, x) => acc + Math.abs(x - median), 0);
        console.log(operations);
        rl.close();
    }
});
